CODE_EXAMPLE:
// Before
class Person {
  public String name;
}

// After
class Person {
  private String name;
  String getName() { return name; }
  void setName(String name) { this.name = name; }
}

UNIT_TEST_EXAMPLE:
@Test
public void testEncapsulateField() {
  Person person = new Person();
  person.setName("John");
  assertEquals("John", person.getName());
}
